        // Map dữ liệu nguồn sang cấu trúc bảng `kanjis`
        $mapItems = function(array $items, string $level): array {
            return array_map(function ($k) use ($level) {
                return [
                    'character'     => $k['character'] ?? null,
                    'meaning'       => $k['description'] ?? null,
                    'on_reading'    => '',
                    'kun_reading'   => '',
                    'level'         => $level,
                    'stroke_count'  => isset($k['stroke_order']) ? (int) $k['stroke_order'] : null,
                    'radical'       => '',
                    'examples'      => null,
                ];
            }, $items);
        };

        $payload = array_merge(
            $mapItems($kanjiN5, 'N5'),
            $mapItems($kanjiN4, 'N4'),
            $mapItems($kanjiN3, 'N3'),
        );

        Kanji::insert($payload);

        $this->command->info('Đã tạo ' . count($payload) . ' Kanji theo chuẩn JLPT:');
        $this->command->info('- N5: ' . count($kanjiN5) . ' chữ');
        $this->command->info('- N4: ' . count($kanjiN4) . ' chữ');
        $this->command->info('- N3: ' . count($kanjiN3) . ' chữ');
    }
